Here's how to create a minimal counter tracking module using Cosmos SDK v0.50 with collections:

```go
// keeper.go
package main

import (
	"context"

	"github.com/cosmos/cosmos-sdk/codec"
	collections "github.com/cosmos/cosmos-sdk/collections/v2alpha1"
)

type CounterKeeper struct {
	collection *collections.Map
}

func NewCounterKeeper(ctx context.Context, storeKey string, cdc codec.Codec) *CounterKeeper {
	mapCollection := collections.NewMap(cdc, storeKey)
	return &CounterKeeper{collection: mapCollection}
}

// GetCount returns the current count for an address or 0 if not set
func (k *CounterKeeper) GetCount(ctx context.Context, addr string) uint64 {
	count, err := k.collection.Get(ctx, addr)
	if err != nil {
		return 0
	}
	return count.(uint64)
}

// Increment increases the count for an address by 1
func (k *CounterKeeper) Increment(ctx context.Context, addr string) error {
	return k.collection.Incr(ctx, addr, 1)
}

// Reset sets the count to 0 for an address
func (k *CounterKeeper) Reset(ctx context.Context, addr string) error {
	return k.collection.Set(ctx, addr, 0)
}
```

```go
// msg_server.go
package main

import (
	"context"

	"github.com/cosmos/cosmos-sdk/grpc/gateway"
)

type MsgServer struct {
	keeper *CounterKeeper
}

func NewMsgServer(keeper *CounterKeeper) *MsgServer {
	return &MsgServer{keeper: keeper}
}

// HandleIncrement increments the counter for the sender's address
func (s *MsgServer) HandleIncrement(ctx context.Context, addr string) (*IncrementResponse, error) {
	err := s.keeper.Increment(ctx, addr)
	if err != nil {
		return nil, err
	}
	return &IncrementResponse{}, nil
}

// HandleReset resets the counter for the sender's address to 0
func (s *MsgServer) HandleReset(ctx context.Context, addr string) (*ResetResponse, error) {
	err := s.keeper.Reset(ctx, addr)
	if err != nil {
		return nil, err
	}
	return &ResetResponse{}, nil
}
```

